import { MyResponse, MyResponseInner } from './interface';

type QueryTaskCenterListParams = {
  bizId: string;
  campaignId: string;
  channelId: string;
  longitude: number;
  latitude: number;
  cityId: number;
};

export type TaskConfig = {
  subTaskConfigs: {
    taskName: string;
    taskId: number;
  }[];
  beginTime: number;
  endTime: number;
  showDoubleImage: boolean;
  title: string;
  awardText: string;
};
export function queryTaskCenterList(data: QueryTaskCenterListParams) {
  return kop.send<
    MyResponse<MyResponseInner<{ groupTaskConfigs: TaskConfig[] }>>,
    QueryTaskCenterListParams
  >('prado.fission.ComponentCampaignFacade.queryTaskCenterList', data);
}

type QueryTaskListParams = {
  taskIds: string;
  lng: number;
  lat: number;
  cityId: number;
};

export type SubTaskResult = {
  status: number;
  taskButton?: string;
  taskSeq: number;
  progressRate: {
    totalValue: number;
    currentValue: number;
  };
  taskManualRightDTO?: {
    rightTypeList?: string[];
    rightName?: string;
    isSingleRedpacket: boolean;
    batchId?: number;
    originPrice?: string;
    multipleNum?: number;
    price?: string;
    /**
     * 如果为true，标识是奖励【手动领奖型任务|访问过活动自动下发】 且没有过领取动作
     */
    getRightReceiveFlag?: boolean;
  };
  subTaskPic: string;
  subTitle: string;
  taskUrl: string;
  mainTitle: string;
  end: number;
  id: number;
  taskInstructions: string;
  begin: number;
};
export type MainTaskResult = {
  id: number;
  issuedAward?: string;
  multipleNum?: number;
  subTaskResultList: SubTaskResult[];
  isMultipleTask: boolean;
  periodBeginTime: number;
  beginTime: number;
  taskCampaignId: number;
  taskSceneType: number;
  taskType: number;
  subTitle: string;
  bizId: string;
  eventNameList: string[];
  periodEndTime: number;
  categoryCode: string;
  priority: number;
  taskWay: number;
  multipleAward: {
    awardDetail: {
      isSingleRedpacket: boolean;
      subTaskId: number;
    }[];
  };
  mainTitle: string;
  originTaskType: number;
  taskPeriod: number;
  endTime: number;
  teamType: number;
  status: number;
};
export function queryTaskList(data: QueryTaskListParams) {
  return kop.send<
    MyResponse<MainTaskResult[]>,
    QueryTaskListParams
  >('prd.task.going.specified.task.list.query', data);
}

type TaskReceiveParams = {
  taskId: number;
  cityId: number;
};

export function taskReceive(data: TaskReceiveParams) {
  return kop.send<MyResponse<boolean>, TaskReceiveParams>(
    'prd.task.receive',
    data,
  );
}

export type TaskReceiveAwardParams = {
  /**
   * 活动id，取值任务查询中返回的taskCampaignId字段
   */
  campaignId: number;
  /**
   * 子任务id，取值任务查询返回的
   */
  subTaskId: number;
  /**
   * 子任务开始时间 取查询列表的periodBeginTime
   */
  beginTime: number;
  /**
   * 子任务结束时间 取查询列表的periodEndTime
   */
  endTime: number;
};

type SubBenefitInfoGrantResults = {
  /**
   * 前端添加字段
   */
  isPackage?: boolean;
  batchName: string;
  benefitType: number;
  status: number;
  benefitEffectiveTime?: number;
  couponType?: number;
  couponMaxAmount?: number;
  limitType?: number;
  limitAmount?: number;
  multiple?: number;
  cyclingCashAmount?: number;
  redEnvelopmentAmount?: number;
