import { PrimitiveAtom } from 'jotai';

export interface IGeolocation {
  success: boolean;
  latitude?: number;
  longitude?: number;
  cityId?: number;
}

export interface LinkConfig {
  wxmp: string;
  alimp: string;
  qjwxmp: string;
  passenger: string;
}

export interface TaskContentImages {
  taskContentOneImg: string;
  taskContentMoreImg: string;
}

export interface CyclingButtonImages {
  completedTwoImg: string;
  completedOneImg: string;
  incompleteTwoImg: string;
  incompleteOneImg: string;
}

export interface SkinConfigure {
  headImgUrl: string;
  headImgAuthUrl: string;
  rewardItemImgUrl: string;
  rewardDefaultImgUrl: string;
  rewardDoubleImgUrl: string;
}

export interface ButtonConfigure {
  close?: {
    buttonImg: string;
    buttonAuthImg: string;
  };
  subscribe?: {
    dialogSubscribeConfig: {
      scene: string;
      pageImage: string;
      buttonImage: string;
    };
    buttonImg: string;
    buttonAuthImg: string;
  };
  link?: {
    linkConfig: LinkConfig;
    buttonImg: string;
    buttonAuthImg: string;
  };
}

export interface QjCashbackProps {
  // 状态管理（可选，SmartGMP可能提供全局store）
  store?: any;
  atomMap?: {
    geolocationAtom: PrimitiveAtom<IGeolocation>;
    seriesTaskInfoAtom: PrimitiveAtom<any>;
  };

  // 图片配置（必填）
  bannerimg: string;
  arrowimg: string;
  taskcontent: TaskContentImages;
  cyclingbtnimage: CyclingButtonImages;

  // 链接配置（必填）
  cyclingincompletelink: LinkConfig;
  cyclingcompletedlink: LinkConfig;

  // 其他配置（可选）
  reminddata?: object;
  status?: Record<string, string>;
  skinConfigure?: SkinConfigure;
  buttonConfigure?: ButtonConfigure;
  subscribeConfig?: object;
  previewVisible?: boolean;
  priority?: number;
  __designMode?: string;

  // SDK注入（可选）
  sdk?: {
    htwSdk?: any;
    mfSdk?: any;
  };

  // API配置（可选）
  apiConfig?: {
    baseUrl?: string;
    headers?: Record<string, string>;
  };

  // Mock数据（可选，用于测试）
  mockData?: {
    taskList?: any[];
    taskCenter?: any;
    award?: any;
  };
}

import { AxiosResponse } from 'axios';

interface UserInfoSuccess {
  login: true;
  token: string;
  phone: string;
  uid: string;
}
interface UserInfoFail {
  login: false;
}
export type UserInfo = UserInfoSuccess | UserInfoFail;

interface GeolocationSuccess {
  success: true;
  latitude: number;
  longitude: number;
  cityId: number;
}
interface GeolocationFail {
  success: false;
}
export type IGeolocation = GeolocationSuccess | GeolocationFail;

export interface LinkConfig {
  wxmp: string;
  alimp: string;
  qjwxmp: string;
  passenger: string;
}

export type XEnv = 'wxmp' | 'alimp' | 'qjwxmp' | 'passenger' | 'h5' | '';

interface SubscribeParams {
  activityId: number | string;
  backUrl?: string;
}

interface HtwSdk {
  xenv: {
    getEnv(): XEnv;
  };
  share: any;
  initWsgsdk: (uid: string) => Promise<void>;

  user: {
    getUserInfo: () => Promise<UserInfo>;
    login: () => Promise<UserInfo>;
    logout: () => Promise<UserInfo>;
  };
  geo: {
    getCurrentPosition: () => Promise<IGeolocation>;
    getCityId: (latitude: number, longitude: number) => Promise<number>;
  };
  kop: {
    http: import('axios').AxiosInstance;
    instance: import('axios').AxiosInstance;
    send<T, P>(api: string, params: P): Promise<AxiosResponse<T>>;
  };
  url: {
    getAllQuery(url: string): Record<string, string>;
    getSupportedImgSrc(src: string): string;
  };
  goto: {
    open(config: LinkConfig): Promise<{ success: boolean; msg?: string }>;
  };
  subscribe: {
    subscribe: (s: SubscribeParams) => void;
  };
}

declare global {
  namespace JSX {
    interface IntrinsicElements {
      [elemName: string]: any;
    }
  }
  interface Window {
    htwSdk: HtwSdk;
    __mf_sdk__: {
      insertAndStartPopQueue: Function;
    };
    baseURL: string;
    Omega: {
      setConfig: (config: Record<string, unknown>) => void;
      trackEvent: (
        eventId: string,
        eventLabel?: string,
        attrs?: Record<string, unknown>,
      ) => void;
    };
    __common_dialog?: {
      handleFn?: () => void;
    };
  }
}

export interface MyResponse<T> {
  code: number;
  msg: string;
  data: T;
}

export interface MyResponseInner<T> {
  code: number;
  success: boolean;
  result: T;
}
export interface CommonAttributes {
  consumeArea?: '0';
  consumePeriodType?: 1;
  couponMaxAmount?: 150;
  couponType?: number;
  payMisProductId?: 251;
  remainBatchNumber?: 6664;
  remainBudget?: 9997;
  remainBudgetCent?: 999700;
  remark?: '电-其一-开19关21005方案';
  ruleAdditionRemark?: '';
}
export interface DiscountRule {
  promotionMethod?: {
    amount: 150;
    maxAmount: 150;
    promotionMethodType: 2;
    ruleDescription: '核销优惠方式：每单可抵1.50元';
    discount?: number;
  };
}
export interface ConsumeRule {
  consumeTime?: {
    ruleDescription: '可核销时间段：周一、周二、周三、周四、周五、周六、周日，全天可用';
    weekdays: ['1', '2', '3', '4', '5', '6', '7'];
  };
  couponConsumeFence?: {
    endFenceIds: ['21005', '18006'];
    fenceType: 2;
    operator: 1;
    startFenceIds: ['19002'];
  };
  consumeChannel?: { limitChannels: ['not_limit_consume_channel'] };
  orderAmount?: { limitType: number; limitAmount: number };
  consumePeriod?: { periodType: 1 };
  consumeArea?: {
    areaSelectType: 1;
    cities: [0];
    ruleDescription: '核销地理范围：全国';
  };
  businessOperator?: { operatorType: 2; ruleDescription: '运营商选择：通用' };
  couponEffectType?: { effectType: 1 };
  consumeVehicleCategory?: {
    categories: [];
    ruleDescription: '核销车型选择：所有车型可用';
  };
}
export interface BenefitConsumeInfo {
  productId: number;
  benefitType: number;
  batchId: number;
  benefitId: string;
}
